mapper.select:
SELECT DISTINCT M.MENU_NO as menuNo, M.MENU_NM as menuNm, M.MENU_URL as menuUrl, M.PARENT_NO as parentNo, M.MENU_ORD as menuOrd, M.ICON_CLASS as iconClass FROM TB_MENU M JOIN TB_ROLE_MENU RM ON M.MENU_NO = RM.MENU_NO WHERE RM.ROLE_CD IN
#{role}
AND M.USE_YN = 'Y' ORDER BY M.PARENT_NO IS NULL DESC, M.PARENT_NO ASC, M.MENU_ORD ASC
